section.script:
/* ── Quantity Counter ─── */
function utChangeQty(change) {
    var input = document.querySelector('input[name="add_qty"]');
    if (!input) return;
    var currentVal = parseInt(input.value) || 1;
    var minVal = parseInt(input.getAttribute('data-min')) || 1;
    var newVal = currentVal + change;
    if (newVal >= minVal) {
        input.value = newVal;
        var event = new Event('change', { bubbles: true });
        input.dispatchEvent(event);
    }
}

/* Share popover */
function utToggleSharePopover(trigger) {
    var popover = document.getElementById('ut-share-popover');
    if (!popover || !trigger) return;
    if (!popover.classList.contains('tw-hidden')) {
        utHideShareModal();
        return;
    }
    var container = document.getElementById('ut-product-main-card');
    if (!container) return;
    var rect = trigger.getBoundingClientRect();
    var containerRect = container.getBoundingClientRect();
    var width = 125;
    var height = 62;
    var gap = 10;
    var left = rect.left - containerRect.left + (rect.width / 2) - (width / 2);
    left = Math.max(12, Math.min(left, containerRect.width - width - 12));
    var top = rect.top - containerRect.top - height - gap;
    if (top < 12) {
        top = rect.bottom - containerRect.top + gap;
    }
    popover.style.left = left + 'px';
    popover.style.top = top + 'px';
    popover.classList.remove('tw-hidden');
    popover.classList.add('tw-flex');
    popover.setAttribute('aria-hidden', 'false');
}
function utHideShareModal() {
    var popover = document.getElementById('ut-share-popover');
    if (!popover) return;
    popover.classList.add('tw-hidden');
    popover.classList.remove('tw-flex');
    popover.setAttribute('aria-hidden', 'true');
}
function utCopyShareLink(btn) {
    var url = window.location.href;
    var icon = btn ? btn.querySelector('i') : null;
    var oldTitle = btn ? btn.getAttribute('aria-label') : '';
    var copied = false;
    function flash() {
        copied = true;
        if (!icon) return;
        var orig = icon.className;
        icon.className = 'fa fa-check';
        icon.style.color = 'var(--ut-color-success)';
        if (btn) btn.setAttribute('aria-label', 'Link berhasil disalin');
        setTimeout(function() {
            icon.className = orig;
            icon.style.color = '';
            if (btn) btn.setAttribute('aria-label', oldTitle || 'Salin link produk');
            utHideShareModal();
        }, 900);
    }
    function fallbackCopy() {
        var ta = document.createElement('textarea');
        ta.value = url;
        ta.setAttribute('readonly', 'readonly');
        ta.style.position = 'fixed';
        ta.style.left = '-9999px';
        document.body.appendChild(ta);
        ta.focus();
        ta.select();
        try {
            document.execCommand('copy');
        } catch (err) {
            console.warn('[UniTrade] Fallback copy failed:', err);
        }
        document.body.removeChild(ta);
        flash();
    }
    if (!navigator.clipboard || !document.hasFocus()) {
        fallbackCopy();
        return;
    }
    try {
        Promise.resolve(navigator.clipboard.writeText(url))
            .then(flash)
            .catch(function() {
                if (!copied) fallbackCopy();
            });
    } catch (err) {
        fallbackCopy();
    }
}
function utShareWhatsApp() {
    var url = encodeURIComponent(window.location.href);
    window.open('https://wa.me/?text=' + url, '_blank');
    utHideShareModal();
}
document.addEventListener('click', function(ev) {
    var popover = document.getElementById('ut-share-popover');
    if (!popover || popover.classList.contains('tw-hidden')) return;
    var target = ev.target;
    if (popover.contains(target)) return;
    var shareTrigger = target.closest ? target.closest('[title="Bagikan"]') : null;
    if (shareTrigger) return;
    utHideShareModal();
});
document.addEventListener('keydown', function(ev) {
    if (ev.key === 'Escape') utHideShareModal();
});
function utSwitchTab(btn, tabName) {
    var tabs = ['deskripsi', 'ulasan'];
    for (var i = 0; i < tabs.length; i++) {
        var panel = document.getElementById('tab-' + tabs[i]);
        var tb = document.getElementById('ut-tab-' + tabs[i]);
        if (panel) panel.style.display = 'none';
        if (tb) tb.classList.remove('ut-product-detail-tab-active');
    }
    var active = document.getElementById('tab-' + tabName);
    if (active) active.style.display = 'block';
    btn.classList.add('ut-product-detail-tab-active');
}

/* ── Gallery thumbnail (IIFE - immediate) ──────── */
(function() {
    function initProductGallery() {
        var mainImg = document.getElementById('ut-main-image');
        var gallery = document.querySelector('.ut-thumbnail-container');
        if (!mainImg || !gallery || gallery.dataset.utGalleryBound === '1') return;

        gallery.dataset.utGalleryBound = '1';
        mainImg.style.transition = 'opacity 180ms ease';

        gallery.addEventListener('click', function(ev) {
            var thumb = ev.target.closest ? ev.target.closest('.ut-thumb') : null;
            if (!thumb || !gallery.contains(thumb)) return;

            var src = thumb.getAttribute('data-src');
            if (!src || mainImg.getAttribute('src') === src) return;

            mainImg.style.opacity = '0.45';

            var nextImage = new Image();
            nextImage.onload = function() {
                mainImg.src = src;
                mainImg.style.opacity = '1';
            };
            nextImage.onerror = function() {
                mainImg.src = src;
                mainImg.style.opacity = '1';
            };
            nextImage.src = src;

            var thumbs = gallery.querySelectorAll('.ut-thumb');
            for (var i = 0; i < thumbs.length; i++) {
                thumbs[i].style.borderColor = 'transparent';
            }
            thumb.style.borderColor = 'var(--ut-color-border-strong)';
        });
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initProductGallery);
    } else {
        initProductGallery();
    }
})();
